mapper.select:
SELECT l.id,
       l.admin_user_id AS adminUserId,
       u.nickname AS adminNickname,
       l.action,
       l.resource_type AS resourceType,
       l.resource_id AS resourceId,
       l.target_user_id AS targetUserId,
       l.before_json AS beforeJson,
       l.after_json AS afterJson,
       l.ip,
       l.user_agent AS userAgent,
       l.created_at AS createdAt
FROM admin_audit_log l
LEFT JOIN users u ON u.id = l.admin_user_id
WHERE 1 = 1
  AND l.admin_user_id = #{adminUserId}
  AND l.action = #{action}
  AND l.resource_type = #{resourceType}
  AND l.target_user_id = #{targetUserId}
  AND l.created_at >= #{from}
  AND l.created_at <= #{to}
ORDER BY l.created_at DESC, l.id DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM admin_audit_log l
WHERE 1 = 1
  AND l.admin_user_id = #{adminUserId}
  AND l.action = #{action}
  AND l.resource_type = #{resourceType}
  AND l.target_user_id = #{targetUserId}
  AND l.created_at >= #{from}
  AND l.created_at <= #{to}
